              added to this profile
            </span>
          )}
        </div>

        <ProductList
          products={products}
          selectedIds={selectedIds}
          onToggle={toggleProduct}
        />

        <Separator />

        <AdjustmentControls
          adjustment={state.adjustment}
          onChange={setAdjustment}
        />

        <div className="flex items-center justify-between">
          <p className="text-sm font-medium">Preview new prices</p>
          <Button variant="ghost" size="sm" className="text-primary">
            <RefreshCcw className="mr-1 size-3.5" />
            Refresh New Price Table
          </Button>
        </div>

        <PreviewTable
          products={selectedProducts}
          adjustment={state.adjustment}
        />

        <div className="flex items-center justify-between pt-2">
          <span className="text-xs text-muted-foreground">
            Your entries are saved automatically
          </span>
          <div className="flex items-center gap-2">
            <Button
              variant="ghost"
              onClick={() => scrollToCard("profile-basic-card")}
            >
              Back
            </Button>
            <Button onClick={() => scrollToCard("assign-customers-card")}>
              Next
            </Button>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

function ScopeRow({
  id,
  value,
  label,
}: {
  id: string;
  value: ProductScope;
  label: string;
}) {
  return (
    <div className="flex items-center gap-2">
      <RadioGroupItem id={id} value={value} />
      <Label htmlFor={id} className="font-normal">
        {label}
      </Label>
    </div>
  );
}
